import{_ as a,c as i,a3 as t,o as e}from"./chunks/framework.VX8o9GSp.js";const c=JSON.parse('{"title":"git 分支操作","description":"","frontmatter":{"date":"2024-04-08T00:00:00.000Z","tags":["git"],"categories":["计算机"]},"headers":[],"relativePath":"2024/04/git 分支操作.md","filePath":"2024/04/git 分支操作.md","lastUpdated":1728736934000}'),h={name:"2024/04/git 分支操作.md"};function n(p,s,l,d,k,o){return e(),i("div",null,s[0]||(s[0]=[t(`<h1 id="git-分支操作" tabindex="-1">git 分支操作 <a class="header-anchor" href="#git-分支操作" aria-label="Permalink to &quot;git 分支操作&quot;">​</a></h1><h2 id="我使用-git-checkout-命令回溯到之前的某个提交-我该如何把仓库彻底固定在当前提交" tabindex="-1">我使用 git checkout 命令回溯到之前的某个提交，我该如何把仓库彻底固定在当前提交 <a class="header-anchor" href="#我使用-git-checkout-命令回溯到之前的某个提交-我该如何把仓库彻底固定在当前提交" aria-label="Permalink to &quot;我使用 git checkout 命令回溯到之前的某个提交，我该如何把仓库彻底固定在当前提交&quot;">​</a></h2><p>如果你想要将仓库彻底固定在当前提交，你可以创建一个新的分支。这样，你就可以在这个新的分支上进行工作，而不会影响到主分支。以下是如何创建新分支的命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new_branch_name</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new_branch_name</span></span></code></pre></div><p>这两行命令首先创建了一个名为 &quot;new_branch_name&quot; 的新分支，然后切换到这个新分支。你需要将 &quot;new_branch_name&quot; 替换为你想要的分支名。</p><h2 id="如何在-git-中删除一个分支" tabindex="-1">如何在 Git 中删除一个分支？ <a class="header-anchor" href="#如何在-git-中删除一个分支" aria-label="Permalink to &quot;如何在 Git 中删除一个分支？&quot;">​</a></h2><p>在 Git 中，你可以使用以下命令来删除一个分支：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch_name</span></span></code></pre></div><p>这个命令会删除名为 &quot;branch_name&quot; 的分支。你需要将 &quot;branch_name&quot; 替换为你想要删除的分支名。</p><p>如果你想要强制删除一个分支，即使它还没有被合并，你可以使用 <code>-D</code> 选项：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -D</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch_name</span></span></code></pre></div><p>请注意，这个操作是不可逆的，所以在执行之前请确保你真的想要删除这个分支。</p><h2 id="我该如何删除远程分支" tabindex="-1">我该如何删除远程分支 <a class="header-anchor" href="#我该如何删除远程分支" aria-label="Permalink to &quot;我该如何删除远程分支&quot;">​</a></h2><p>在 Git 中，你可以使用以下命令来删除一个远程分支：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch_name</span></span></code></pre></div><p>这个命令会删除名为 &quot;branch_name&quot; 的远程分支。你需要将 &quot;branch_name&quot; 替换为你想要删除的远程分支名。</p><p>请注意，这个操作是不可逆的，所以在执行之前请确保你真的想要删除这个远程分支。</p><h2 id="重命名分支" tabindex="-1">重命名分支 <a class="header-anchor" href="#重命名分支" aria-label="Permalink to &quot;重命名分支&quot;">​</a></h2><p>在 Git 中，你可以使用以下命令来重命名一个分支：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> old_branch_name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new_branch_name</span></span></code></pre></div><p>这个命令会将名为 &quot;old_branch_name&quot; 的分支重命名为 &quot;new_branch_name&quot;。你需要将 &quot;old_branch_name&quot; 和 &quot;new_branch_name&quot; 替换为你想要的分支名。</p><p>如果你当前已经在 &quot;old_branch_name&quot; 分支上，你可以省略 &quot;old_branch_name&quot;，直接使用以下命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new_branch_name</span></span></code></pre></div><hr><p>把本地的 main 分支与远程 main 分支绑定</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set-upstream-to=origin/main</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><h2 id="如何把一个本地分支与一个远程分支建立联系" tabindex="-1">如何把一个本地分支与一个远程分支建立联系 <a class="header-anchor" href="#如何把一个本地分支与一个远程分支建立联系" aria-label="Permalink to &quot;如何把一个本地分支与一个远程分支建立联系&quot;">​</a></h2><p>你可以使用 <code>git branch --set-upstream-to</code> 命令来将一个本地分支与一个远程分支建立联系。这个命令会设置远程分支为本地分支的上游分支。</p><p>以下是具体的命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set-upstream-to=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">remote</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">branch</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">local-branc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">h</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>这里的 <code>&lt;remote&gt;</code> 是远程仓库的名字，<code>&lt;branch&gt;</code> 是远程分支的名字，<code>&lt;local-branch&gt;</code> 是本地分支的名字。</p><p>例如，如果你想将本地的 <code>master</code> 分支与 <code>origin</code> 远程仓库的 <code>master</code> 分支建立联系，你可以使用以下命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set-upstream-to=origin/master</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> master</span></span></code></pre></div><p>设置上游分支后，你可以使用 <code>git pull</code> 和 <code>git push</code> 命令来拉取和推送更改，而不需要每次都指定远程仓库和分支的名字。</p>`,34)]))}const g=a(h,[["render",n]]);export{c as __pageData,g as default};
